cleanup.query:
mutation OrderEditShippingLineValidationCancel(
    $orderId: ID!
    $reason: OrderCancelReason!
    $notifyCustomer: Boolean!
    $restock: Boolean!
  ) {
    orderCancel(orderId: $orderId, reason: $reason, notifyCustomer: $notifyCustomer, restock: $restock) {
      job {
        id
      }
      userErrors {
        field
        message
      }
    }
  }

upstreamCalls.query:
query OrdersOrderEditHydrate($id: ID!) {
  order(id: $id) {
    id
    name
    merchantEditable
    cancelledAt
    cancelReason
    displayFinancialStatus
    lineItems(first: 50) {
      nodes {
        id
        title
        quantity
        currentQuantity
        sku
        variant {
          id
          title
          sku
        }
        originalUnitPriceSet {
          shopMoney {
            amount
            currencyCode
          }
        }
      }
    }
  }
}
